    "\n",
    "# Define save paths relative to the repo root\n",
    "out_parquet = Path(\"_data\") / \"option_implied_rates_1996_2022.parquet\"\n",
    "out_csv = Path(\"_data\") / \"option_implied_rates_1996_2022.csv\"\n",
